import React from 'react';

const LoginView = ({
    loginView,
    gameId,
    roomPassword,
    playerName,
    setLoginView,
    setGameId,
    setRoomPassword,
    setPlayerName,
    createPassword,
    setCreatePassword,
    joinRoomCode,
    setJoinRoomCode,
    joinRoomPin,
    setJoinRoomPin,
    availableRooms,
    loadingRooms,
    fetchRooms,
    selectedRoom,
    setSelectedRoom,
    handleJoinGame,
    handleFinalJoin,
    pendingJoin,
    setPendingJoin,
    setMessage,
    setMessageType,
    SOCKET_URL,
    setURLRoom,
    gameTimeLimit,
    setGameTimeLimit,
    roomNotFound,
}) => {
    return (
        <div className="max-w-md mx-auto space-y-4 pt-4">
            <div className="text-center space-y-2">
                <div className="relative inline-block">
                    <div className="text-6xl sm:text-7xl animate-bounce" style={{ animationDuration: '2s' }}>⚓</div>
                    <div className="absolute -top-1 -right-3 bg-yellow-500 text-[0.5rem] font-black text-slate-900 px-1.5 py-0.5 rounded-full shadow-md">v2</div>
                </div>
                <h2 className="text-3xl sm:text-4xl font-black bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400 bg-clip-text text-transparent">Play Battleships</h2>
                <div className="flex items-center justify-center gap-2 text-slate-400 text-sm">
                    <span className="w-8 h-px bg-slate-600" />
                    <span>2-player · real-time · strategy</span>
                    <span className="w-8 h-px bg-slate-600" />
                </div>
            </div>

            {/* MENU VIEW */}
            {loginView === 'menu' && !gameId && (
                <div className="space-y-3">
                    <button
                        onClick={() => setLoginView('create')}
                        className="group w-full py-4 bg-gradient-to-r from-emerald-500 to-green-500 hover:from-emerald-400 hover:to-green-400 text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg shadow-emerald-900/30 text-base flex items-center justify-center gap-2"
                    >
                        <span className="text-xl group-hover:rotate-12 transition-transform">⚔️</span> Create Game
                    </button>
                    <button
                        onClick={() => setLoginView('join')}
                        className="group w-full py-4 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg shadow-purple-900/30 text-base flex items-center justify-center gap-2"
                    >
                        <span className="text-xl group-hover:translate-x-1 transition-transform">⛵</span> Join Game
                    </button>
                </div>
            )}

            {/* URL JOIN VIEW */}
            {(gameId && loginView !== 'create' && loginView !== 'enterName') && (
                roomNotFound ? (
                    <div className="space-y-4">
                        <div className="bg-red-900/30 border border-red-500/50 rounded-2xl p-5 text-center space-y-2">
                            <div className="text-4xl">🚫</div>
                            <p className="text-red-300 font-bold text-lg">Room Not Found</p>
                            <p className="text-slate-400 text-sm">
                                The room <span className="font-mono font-bold text-yellow-300">{gameId}</span> doesn't exist or has already closed.
                            </p>
                        </div>
                        <button
                            onClick={() => { setURLRoom(null); setGameId(''); setLoginView('menu'); }}
                            className="w-full py-3 bg-slate-700 hover:bg-slate-600 text-white font-bold rounded-2xl transition-all"
                        >
                            ← Back to Menu
                        </button>
                    </div>
                ) : (
                    <div className="space-y-4">
                    <div className="bg-blue-900/30 border border-blue-500/50 rounded-2xl p-4 text-center">
                        <p className="text-blue-300 text-sm mb-1">You've been invited to join:</p>
                        <p className="text-2xl font-black font-mono text-yellow-300 tracking-widest">{gameId}</p>
                        {roomPassword && <p className="text-xs text-green-400 mt-2">🔒 PIN: <span className="font-mono font-bold">{roomPassword}</span></p>}
                    </div>
                    {!roomPassword && (
                        <div className="bg-slate-800/80 rounded-2xl p-4 border border-slate-700 space-y-2">
                            <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">PIN (if required)</label>
                            <input
                                type="text"
                                inputMode="numeric"
                                value={roomPassword || ''}
                                onChange={e => setRoomPassword(e.target.value.replace(/\D/g, '').slice(0, 3))}
                                maxLength={3}
                                placeholder="123"
                                className="w-full px-4 py-2.5 bg-slate-700 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono tracking-[0.5em] text-center text-lg"
                            />
                        </div>
                    )}
                    <button
                        onClick={() => {
                            setPendingJoin({ roomId: gameId, password: roomPassword || null });
                            setLoginView('enterName');
                        }}
                        className="w-full py-3.5 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg text-base"
                    >
                        ⛵ Join Game
                    </button>
                    <button
                        onClick={() => { setGameId(''); setRoomPassword(''); setURLRoom(null); setLoginView('menu'); }}
                        className="w-full py-2.5 bg-slate-700 hover:bg-slate-600 text-slate-300 font-semibold rounded-xl transition text-sm"
                    >
                        ← Back to Menu
                    </button>
                    </div>
                )
            )}

            {/* CREATE VIEW */}
            {loginView === 'create' && !gameId && (
                <div className="space-y-4 animate-fade-in">
                    <div className="bg-gradient-to-br from-slate-800/90 to-slate-900/90 rounded-2xl p-5 border border-emerald-500/20 space-y-4 shadow-lg shadow-emerald-900/10">
                        <h3 className="text-lg font-bold text-white flex items-center gap-2">⚔️ Create New Game</h3>
                        <div className="space-y-2">
                            <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">PIN Code (Optional)</label>
                            <input
                                type="text"
                                inputMode="numeric"
                                value={createPassword}
                                onChange={e => setCreatePassword(e.target.value.replace(/\D/g, '').slice(0, 3))}
                                maxLength={3}
                                placeholder="123"
                                className="w-full px-4 py-3 bg-slate-700/80 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-emerald-500/50 font-mono tracking-[0.5em] text-center text-2xl transition-all"
                            />
                            <p className="text-[0.65rem] text-slate-500">🔒 3 digits only. Leave empty for public room</p>
                        </div>

                        <div className="space-y-2 pt-2 border-t border-slate-700/50">
                            <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">Time Per Player</label>
                            <div className="flex items-center gap-3">
                                <input
                                    type="range"
                                    min={2}
                                    max={10}
                                    value={Math.round((gameTimeLimit || 300) / 60)}
                                    onChange={e => setGameTimeLimit(parseInt(e.target.value) * 60)}
                                    className="flex-1 accent-emerald-500"
                                />
                                <span className="text-lg font-mono font-bold text-emerald-300 w-16 text-center bg-emerald-500/10 rounded-lg py-1">{Math.round((gameTimeLimit || 300) / 60)} min</span>
                            </div>
                            <p className="text-[0.65rem] text-slate-500">⏱️ Each player gets this much time — clock only ticks on your turn</p>
                        </div>

                        <button
                            onClick={() => {
                                if (createPassword && createPassword.length !== 3) { setMessage('❌ PIN must be exactly 3 digits'); setMessageType('error'); return; }
                                const id = Math.random().toString(36).slice(2, 8).toUpperCase();
                                setPendingJoin({ roomId: id, password: createPassword || null, isCreating: true, timeLimit: gameTimeLimit || 300 });
                                setLoginView('enterName');
                            }}
                            className="w-full py-3.5 bg-gradient-to-r from-emerald-500 to-green-500 hover:from-emerald-400 hover:to-green-400 text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg shadow-emerald-900/20 text-base"
                        >
                            🚀 Create Game
                        </button>
                    </div>
                    <button
                        onClick={() => setLoginView('menu')}
                        className="w-full py-2.5 bg-slate-700 hover:bg-slate-600 text-slate-300 font-semibold rounded-xl transition text-sm"
                    >
                        ← Back to Menu
                    </button>
                </div>
            )}

            {/* JOIN VIEW */}
            {loginView === 'join' && !gameId && (
                <div className="space-y-4">
                    <div className="bg-slate-800/80 rounded-2xl p-4 border border-slate-700 space-y-3">
                        <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">Room Code</label>
                        <input
                            type="text"
                            value={joinRoomCode}
                            onChange={e => setJoinRoomCode(e.target.value.toUpperCase().replace(/[^A-Z0-9]/g, ''))}
                            maxLength={10}
                            placeholder="A3F9KX"
                            className="w-full px-4 py-3 bg-slate-700 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono tracking-[0.3em] text-center text-xl"
                        />
                        <div className="space-y-2">
                            <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest">PIN (if required)</label>
                            <input
                                type="text"
                                inputMode="numeric"
                                value={joinRoomPin}
                                onChange={e => setJoinRoomPin(e.target.value.replace(/\D/g, '').slice(0, 3))}
                                maxLength={3}
                                placeholder="123"
                                className="w-full px-4 py-2.5 bg-slate-700 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono tracking-[0.5em] text-center text-lg"
                            />
                        </div>
                        <button
                            onClick={handleJoinGame}
                            disabled={!joinRoomCode.trim()}
                            className="w-full py-3 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-xl transition-all hover:scale-[1.02]"
                        >
                            ⛵ Join Room
                        </button>
                    </div>

                    <div className="bg-slate-800/80 rounded-2xl p-4 border border-slate-700 space-y-3">
                        <div className="flex items-center justify-between">
                            <label className="text-xs font-semibold text-slate-400 uppercase tracking-widest">Open Rooms</label>
                            <button
                                onClick={fetchRooms}
                                disabled={loadingRooms}
                                className="text-xs text-blue-400 hover:text-blue-300 disabled:opacity-50"
                            >
                                {loadingRooms ? '⏳' : '🔄'} Refresh
                            </button>
                        </div>

                        {loadingRooms ? (
                            <div className="text-center py-4 text-slate-500 text-sm">Loading rooms...</div>
                        ) : availableRooms.length === 0 ? (
                            <div className="text-center py-4 text-slate-500 text-sm">
                                No open rooms available<br />
                                <span className="text-xs">Create a game or enter a room code above</span>
                            </div>
                        ) : (
                            <div className="space-y-2 max-h-48 overflow-y-auto">
                                {availableRooms.map(room => (
                                    <div key={room.roomId} className="bg-slate-700/50 rounded-xl overflow-hidden">
                                        <button
                                            onClick={() => {
                                                if (room.hasPassword) {
                                                    setSelectedRoom(selectedRoom === room.roomId ? null : room.roomId);
                                                    setJoinRoomPin('');
                                                } else if (room.state === 'WAITING_FOR_PLAYERS') {
                                                    setPendingJoin({ roomId: room.roomId, password: null });
                                                    setLoginView('enterName');
                                                } else {
                                                    // In-progress game — spectate
                                                    setPendingJoin({ roomId: room.roomId, password: null, isSpectating: true });
                                                    setLoginView('enterName');
                                                }
                                            }}
                                            className="w-full flex items-center justify-between p-3 hover:bg-slate-600/50 transition text-left"
                                        >
                                            <div>
                                                <span className="font-mono font-bold text-yellow-300 tracking-wider">{room.roomId}</span>
                                                <span className="text-slate-400 text-sm ml-2">by {room.hostName}</span>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                {room.hasPassword ? (
                                                    <span className="text-xs bg-orange-500/20 text-orange-300 px-2 py-0.5 rounded-full">🔒 PIN</span>
                                                ) : room.state !== 'WAITING_FOR_PLAYERS' ? (
                                                    <span className="text-xs bg-purple-500/20 text-purple-300 px-2 py-0.5 rounded-full">👁️ Spectate</span>
                                                ) : (
                                                    <span className="text-xs bg-green-500/20 text-green-300 px-2 py-0.5 rounded-full">✓ Open</span>
                                                )}
                                            </div>
                                        </button>
                                        {room.hasPassword && selectedRoom === room.roomId && (
                                            <div className="px-3 pb-3 pt-1 bg-slate-600/30 space-y-2">
                                                <div className="flex gap-2 items-center">
                                                    <input
                                                        type="text"
                                                        inputMode="numeric"
                                                        value={joinRoomPin}
                                                        onChange={e => setJoinRoomPin(e.target.value.replace(/\D/g, '').slice(0, 3))}
                                                        maxLength={3}
                                                        placeholder="PIN"
                                                        autoFocus
                                                        className="flex-1 px-3 py-2 bg-slate-700 border border-slate-600 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500 font-mono tracking-[0.3em] text-center"
                                                    />
                                                    <button
                                                        onClick={async () => {
                                                            if (joinRoomPin.length !== 3) {
                                                                setMessage('❌ PIN must be 3 digits'); setMessageType('error');
                                                                return;
                                                            }
                                                            try {
                                                                const res = await fetch(`${SOCKET_URL}/rooms/${room.roomId}/check-password`, {
                                                                    method: 'POST',
                                                                    headers: { 'Content-Type': 'application/json' },
                                                                    body: JSON.stringify({ password: joinRoomPin })
                                                                });
                                                                const data = await res.json();
                                                                if (data.valid) {
                                                                    setPendingJoin({ roomId: room.roomId, password: joinRoomPin });
                                                                    setLoginView('enterName');
                                                                } else {
                                                                    setMessage(`❌ ${data.error || 'Incorrect PIN'}`); setMessageType('error');
                                                                }
                                                            } catch (err) {
                                                                setMessage('❌ Failed to validate PIN'); setMessageType('error');
                                                            }
                                                        }}
                                                        disabled={joinRoomPin.length !== 3}
                                                        className="px-4 py-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-lg transition"
                                                    >
                                                        Join
                                                    </button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>

                    <button
                        onClick={() => { setLoginView('menu'); setJoinRoomCode(''); setJoinRoomPin(''); }}
                        className="w-full py-2.5 bg-slate-700 hover:bg-slate-600 text-slate-300 font-semibold rounded-xl transition text-sm"
                    >
                        ← Back to Menu
                    </button>
                </div>
            )}

            {/* ENTER NAME VIEW */}
            {loginView === 'enterName' && pendingJoin && (
                <div className="space-y-4">
                    <div className="bg-blue-900/30 border border-blue-500/50 rounded-2xl p-4 text-center">
                        <p className="text-blue-300 text-sm mb-1">{pendingJoin.isCreating ? 'Creating room:' : 'Joining room:'}</p>
                        <p className="text-2xl font-black font-mono text-yellow-300 tracking-widest">{pendingJoin.roomId}</p>
                        {pendingJoin.password && <p className="text-xs text-green-400 mt-2">🔒 PIN: <span className="font-mono font-bold">{pendingJoin.password}</span></p>}
                    </div>
                    <div className="bg-slate-800/80 rounded-2xl p-4 border border-slate-700">
                        <label className="block text-xs font-semibold text-slate-400 uppercase tracking-widest mb-2">Your Name</label>
                        <input
                            type="text"
                            value={playerName}
                            onChange={e => setPlayerName(e.target.value)}
                            onKeyDown={e => {
                                if (e.key === 'Enter' && playerName.trim()) {
                                    handleFinalJoin();
                                }
                            }}
                            maxLength={50}
                            placeholder="Captain Hook"
                            autoFocus
                            className="w-full px-4 py-3 bg-slate-700 border border-slate-600 rounded-xl text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-blue-500"
                        />
                    </div>
                    <button
                        onClick={handleFinalJoin}
                        disabled={!playerName.trim()}
                        className="w-full py-3.5 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-bold rounded-2xl transition-all hover:scale-[1.02] shadow-lg text-base"
                    >
                        {pendingJoin.isCreating ? '🚀 Create & Join' : '⛵ Join Game'}
                    </button>
                    <button
                        onClick={() => {
                            setLoginView(pendingJoin.isCreating ? 'create' : (gameId ? 'menu' : 'join'));
                            setPendingJoin(null);
                            if (gameId) { setGameId(''); setRoomPassword(''); setURLRoom(null); }
                        }}
                        className="w-full py-2.5 bg-slate-700 hover:bg-slate-600 text-slate-300 font-semibold rounded-xl transition text-sm"
                    >
                        ← Back
                    </button>
                </div>
            )}
        </div>
    );
};

export default LoginView;
